SELECT label, COUNT(contig_id) AS contig_count
FROM contigs
GROUP BY label;

SELECT MAX(length) AS max_length
FROM contigs
WHERE project_id = 1;

SELECT contig_id, length, functional_annotation
FROM contigs
WHERE contig_id = 1;

SELECT contig_id, label, gene_count
FROM contigs
ORDER BY gene_count DESC;
